import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.7R1OEGYz.js";const p=JSON.parse('{"title":"What is Suho","description":"","frontmatter":{},"headers":[],"relativePath":"overview/what-is-suho.md","filePath":"overview/what-is-suho.md"}'),r={name:"overview/what-is-suho.md"};function n(i,e,d,h,l,c){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="what-is-suho" tabindex="-1">What is Suho <a class="header-anchor" href="#what-is-suho" aria-label="Permalink to &quot;What is Suho&quot;">​</a></h1><p>Suho is a guardian wallet on GIWA Sepolia. It puts identity at the center of every payment. You send to names, not addresses. The wallet tells you who you are paying. You recover a lost device without a seed phrase.</p><p>The name is Korean. 수호 means to guard or protect. The visual language is Korean-modern: warm paper, ink text, one red seal.</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><ul><li><strong>Send to names.</strong> Type a up.id name. Suho resolves it on chain and shows a red seal if the recipient is a verified human.</li><li><strong>Warn on strangers.</strong> An unverified recipient shows an amber warning. Small sends still go through. Large sends stop for a code.</li><li><strong>Recover with Arise.</strong> Lost your device? Rotate to a new passkey with a single-use code. Your address and name stay the same.</li><li><strong>Carry a Card.</strong> An attested identity card, signed by your own account, with a walkable version history on EAS.</li></ul><h2 id="what-makes-it-different" tabindex="-1">What makes it different <a class="header-anchor" href="#what-makes-it-different" aria-label="Permalink to &quot;What makes it different&quot;">​</a></h2><p>Your account is a passkey-controlled smart account at your own address. There is no seed phrase. Day to day, a passkey signs every transaction. A guardian service relays those transactions and pays the gas. It never sees a private key.</p><p>New users start from nothing. A fresh browser becomes a verified, named account in a few taps. The one-time key that bootstraps the account is generated in the browser, used to sign twice, and destroyed. See <a href="/docs/internals/custody.html">Custody and threat model</a>.</p><h2 id="live-on-giwa-sepolia" tabindex="-1">Live on GIWA Sepolia <a class="header-anchor" href="#live-on-giwa-sepolia" aria-label="Permalink to &quot;Live on GIWA Sepolia&quot;">​</a></h2><p>Every claim in these docs links to a real transaction. The account layer, the guard, recovery, and the identity card all run on GIWA Sepolia today. Contract addresses are on the <a href="/docs/developers/contracts.html">Contracts and addresses</a> page.</p>',10)])])}const m=a(r,[["render",n]]);export{p as __pageData,m as default};
